{
  "executive_summary": "The payment processing service requirements contain a direct contradiction between customer-managed encryption keys (CMK) and offline operation, plus a significant tension between field-level audit logging and 50ms P99 latency. CMK fundamentally means the customer retains control of key material in an external KMS and can revoke access at any time — caching keys locally to enable offline operation undermines this security guarantee. These trade-offs require business/product decisions before architecture can proceed.",

  "architecture": {
    "components": [
      { "name": "Payment Gateway", "responsibility": "Accepts and validates incoming payment requests, routes to processing pipeline", "boundaries": "Ingress only — no direct access to encryption or persistence layers" },
      { "name": "Encryption Envelope Service", "responsibility": "Manages data encryption keys (DEKs) wrapped by customer master keys, handles envelope encryption/decryption", "boundaries": "Only component that touches plaintext DEKs; all key material stays in-process memory" },
      { "name": "Key Cache (contested)", "responsibility": "Local cache of unwrapped DEKs or CMKs to enable offline operation and low latency", "boundaries": "THIS IS THE CONTESTED COMPONENT — its existence contradicts the CMK security model" },
      { "name": "Audit Logger", "responsibility": "Records every field-level access with actor, timestamp, field name, and operation type", "boundaries": "Must be on the hot path if synchronous guarantees are required; can be async if eventual consistency is acceptable" },
      { "name": "Payment Processor", "responsibility": "Core payment logic — authorization, capture, settlement orchestration", "boundaries": "Operates only on decrypted data within the encryption envelope boundary" },
      { "name": "Key Rotation Orchestrator", "responsibility": "Manages 30-day key rotation: generates new DEKs, re-wraps under new CMK version, background re-encryption of data at rest", "boundaries": "Runs as background process; never blocks payment processing" }
    ],
    "interfaces": [
      { "from": "Payment Gateway", "to": "Encryption Envelope Service", "contract": "encrypt(plaintext, customer_id) → ciphertext + wrapped_dek; decrypt(ciphertext, wrapped_dek, customer_id) → plaintext", "coupling_type": "synchronous — on critical path" },
      { "from": "Encryption Envelope Service", "to": "External KMS (customer-managed)", "contract": "unwrapKey(wrapped_dek, cmk_id) → dek; wrapKey(dek, cmk_id) → wrapped_dek", "coupling_type": "synchronous with contested fallback to cache" },
      { "from": "Payment Processor", "to": "Audit Logger", "contract": "logAccess(actor, field, operation, timestamp, context)", "coupling_type": "synchronous OR async — contested based on requirement interpretation" },
      { "from": "Key Rotation Orchestrator", "to": "Encryption Envelope Service", "contract": "rotateKeys(customer_id) → re-wraps all active DEKs under new CMK version", "coupling_type": "asynchronous background" }
    ],
    "data_flow": "Request → Gateway → Encryption Envelope (decrypt via DEK, DEK unwrapped via CMK from KMS or cache) → Payment Processor (operates on plaintext, each field access logged) → Encryption Envelope (re-encrypt) → Persistence. Key rotation runs as background sweep: new CMK version → re-wrap existing DEKs → background re-encrypt data at rest.",
    "patterns_used": []
  },

  "domain_model": {
    "bounded_contexts": [
      { "name": "Payment Processing", "classification": "core", "aggregates": ["Payment", "PaymentMethod", "Settlement"] },
      { "name": "Encryption & Key Management", "classification": "supporting", "aggregates": ["EncryptionEnvelope", "DataEncryptionKey", "KeyRotationPolicy"] },
      { "name": "Audit & Compliance", "classification": "supporting", "aggregates": ["AuditEntry", "FieldAccessLog"] }
    ],
    "context_map": [
      { "upstream": "External KMS (customer-managed)", "downstream": "Encryption & Key Management", "relationship": "Conformist — we must conform to the customer's KMS API and key policies, which is exactly why offline operation is problematic" },
      { "upstream": "Payment Processing", "downstream": "Audit & Compliance", "relationship": "Customer-Supplier — Payment Processing emits events that Audit consumes" }
    ]
  },

  "trade_offs": [
    {
      "decision": "Local key caching for offline + latency (if contradiction is resolved in favor of availability)",
      "gains": "Meets 50ms P99 and offline requirements",
      "sacrifices": "Breaks CMK security model — customer cannot instantly revoke access; cached keys survive revocation until TTL expires; potential compliance violations (PCI-DSS, SOC2)",
      "alternatives_considered": ["No caching (honors CMK but fails offline + likely fails latency)", "HSM-based local key escrow (expensive, complex, still doesn't honor instant revocation)", "Dual-key scheme where service holds its own key + CMK wraps it (changes the security model entirely)"]
    },
    {
      "decision": "Synchronous vs asynchronous audit logging",
      "gains": "Async: easily meets 50ms P99. Sync: guarantees no unaudited access.",
      "sacrifices": "Async: field access could occur without audit record if process crashes between access and log write. Sync: adds 2-10ms per field access to hot path, likely blows 50ms budget with multiple fields.",
      "alternatives_considered": ["Write-ahead audit log (log before access, compensate on failure)", "Kernel-level eBPF tracing (complex, non-portable)", "Append-only audit stream with guaranteed delivery (Kafka + exactly-once)"]
    }
  ],

  "flexibility_points": [
    { "area": "Envelope encryption pattern", "evolution_path": "DEKs can be re-wrapped under new CMK versions without re-encrypting data — enables zero-downtime key rotation regardless of how the CMK contradiction is resolved" },
    { "area": "Audit transport", "evolution_path": "Audit logger interface can swap between sync and async implementations behind an abstraction once the durability requirement is clarified" }
  ],

  "rigidity_points": [
    { "area": "KMS integration contract", "reason": "We are Conformist to the customer's KMS — their API, latency, and availability characteristics constrain our design fundamentally" },
    { "area": "Encryption on critical path", "reason": "Encryption/decryption is inherently on the hot path for payment data — cannot be deferred or made eventually consistent" }
  ],

