    { "risk": "Key rotation re-encryption backlog — 30-day rotation with large data volumes could create unbounded background work", "severity": "medium", "mitigation": "Envelope encryption means only DEKs need re-wrapping (small), not re-encrypting all data; data re-encryption can be lazy or scheduled" },
    { "risk": "Compliance failure — PCI-DSS auditors may reject local key caching as violating CMK intent", "severity": "critical", "mitigation": "Requires compliance team sign-off before architecture proceeds" }
